/* 代码头注释：完全背包问题 - 动态规划解法
   关键技巧：使用一维数组优化空间复杂度，内层循环正向遍历以实现完全背包特性 */
#include <bits/stdc++.h>
using namespace std;
using ll = long long;
const int INF = 0x3f3f3f3f;

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int n, W;
    cin >> n;
    vector<int> w(n), v(n);
    for (int i = 0; i < n; ++i) {
        cin >> w[i] >> v[i];
    }
    cin >> W;

