    for (int i = 0; i < n; ++i) {
        for (int j = w[i]; j <= W; ++j) {
            dp[j] = max(dp[j], dp[j - w[i]] + v[i]);  // 状态转移方程
        }
    }

    cout << dp[W] << endl;  // 输出最大价值

    return 0;
}
