double E[MAXN];                  // 期望路径长度

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    // 输入
    cin >> N >> M;
    for (int i = 0; i < M; i++) {
        int a, b, c;
        cin >> a >> b >> c;
        G[a].emplace_back(b, c);
        outDegree[a]++;
    }

    // 拓扑排序
    queue<int> q;
    for (int i = 1; i <= N; i++) {
        if (outDegree[i] == 0) {
            q.push(i);
        }
    }

    // 动态规划计算期望值
    while (!q.empty()) {
        int u = q.front();
        q.pop();
        for (auto [v, c] : G[u]) {
            E[u] += (c + E[v]) / outDegree[u];
        }
        for (int i = 1; i <= N; i++) {
            for (auto [v, c] : G[i]) {
                if (v == u) {
                    outDegree[i]--;
                    if (outDegree[i] == 0) {
                        q.push(i);
                    }
                }
            }
        }
    }

    // 输出结果，保留两位小数
    cout << fixed << setprecision(2) << E[1] << endl;

    return 0;
}
```

